#!/bin/bash
# Optional script to enable quiet mode for pre-commit hooks
# This filters out "Skipped" messages to make the output cleaner

set -euo pipefail

HOOK_FILE=".git/hooks/pre-commit"

if [ ! -f "$HOOK_FILE" ]; then
    echo "Error: Pre-commit hook not found. Please run 'pre-commit install' first."
    exit 1
fi

# Extract INSTALL_PYTHON from existing hook
INSTALL_PYTHON=$(grep "^INSTALL_PYTHON=" "$HOOK_FILE" | head -n1 || echo "")

# Backup the original hook
cp "$HOOK_FILE" "$HOOK_FILE.backup"

# Create new hook with filtering
cat > "$HOOK_FILE" << HOOK_EOF
#!/usr/bin/env bash
# File generated by pre-commit: https://pre-commit.com
# Modified to filter "Skipped" messages

# start templated
${INSTALL_PYTHON}
ARGS=(hook-impl --config=.pre-commit-config.yaml --hook-type=pre-commit)
# end templated

HERE="$(cd "$(dirname "$0")" && pwd)"
ARGS+=(--hook-dir "$HERE" -- "$@")

if [ -x "$INSTALL_PYTHON" ]; then
    "$INSTALL_PYTHON" -mpre_commit "${ARGS[@]}" 2>&1 | grep -v "(no files to check)Skipped"
    exit ${PIPESTATUS[0]}
elif command -v pre-commit > /dev/null; then
    pre-commit "${ARGS[@]}" 2>&1 | grep -v "(no files to check)Skipped"
    exit ${PIPESTATUS[0]}
else
    echo '`pre-commit` not found.  Did you forget to activate your virtualenv?' 1>&2
    exit 1
fi
HOOK_EOF

# Make executable
chmod +x "$HOOK_FILE"

echo "✓ Pre-commit quiet mode enabled"
echo "  Skipped hooks will no longer be displayed"
echo "  Original hook backed up to .git/hooks/pre-commit.backup"
